codes.c:
#include <stdio.h>

int sumWithLoop() {
  int sum = 0;
  for (int i = 1; i <= 100; i++) {
    sum += i;
  }
  return sum;
}

int sumWithFormula() {
  return (100 * 101) / 2;
}

int main() {
  printf("Loop Sum: %d\n", sumWithLoop());
  printf("Formula Sum: %d\n", sumWithFormula());
  return 0;
}
// Output:
// Loop Sum: 5050
// Formula Sum: 5050

